import numpy as np

def mean_average_precision(relevance_lists: list[list[int]]) -> float:
    aps = []
    for rel in relevance_lists:
        rel = np.asarray(rel)
        n_relevant = int(np.sum(rel))
        if n_relevant == 0:
            aps.append(0.0)
            continue
        hits, ap = 0, 0.0
        for k, r in enumerate(rel, 1):
            if r == 1:
                hits += 1
                ap += hits / k
        aps.append(ap / n_relevant)
    return float(np.mean(aps))
